import{_ as e,c as r,o as t,V as a}from"./chunks/framework.BPkfcHrH.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{"sidebarDepth":3},"headers":[],"relativePath":"history.md","filePath":"history.md"}'),o={name:"history.md"},n=a('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="v2-7-0-not-yet-released" tabindex="-1">v2.7.0 - Not yet released <a class="header-anchor" href="#v2-7-0-not-yet-released" aria-label="Permalink to &quot;v2.7.0 - Not yet released&quot;">​</a></h2><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/16" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/16" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-6-0-not-yet-released" tabindex="-1">v2.6.0 - Not yet released <a class="header-anchor" href="#v2-6-0-not-yet-released" aria-label="Permalink to &quot;v2.6.0 - Not yet released&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Enhanced zoom control,<br> 👉 More options now available for geodesic objects,<br> 👉 Ability to use distributed contextual services.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 Move to new Téléray public API linked to <a href="https://github.com/kalisio/k-teleray" target="_blank" rel="noreferrer">upgraded krawler job</a>.</p><p><strong>Major bug fixes:</strong><br> ✅ Possible XSS when editing objects or with error messages as query parameter,<br> ✅ Timezone/Location map now uses global catalog when a contextual one is available,<br> ✅ Layers and categories display order not correctly updated when removed,<br> ✅ Window pin coordinates now accounts for header or footer.</p><p><strong>No major breaking changes reported for customized versions or iframe integration use cases.</strong>.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/15" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/15" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-5-0-october-10th-2025" tabindex="-1">v2.5.0 - October 10th, 2025 <a class="header-anchor" href="#v2-5-0-october-10th-2025" aria-label="Permalink to &quot;v2.5.0 - October 10th, 2025&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Improved layer styling management,<br> 👉 Added a tag manager to classify styles,<br> 👉 Enhance coordinates parsing to support more formats in search tool,<br> 👉 Allow to manage layers and categories display order by drag&#39;n&#39;drop,<br> 👉 Ability to animate moving/rotating objects in globe from iframe API.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 French weather stations data layer linked to <a href="https://github.com/kalisio/k-meteofrance" target="_blank" rel="noreferrer">new krawler job</a>,<br> 👉 Move to OpenAQ v3 API linked to <a href="https://github.com/kalisio/k-openaq" target="_blank" rel="noreferrer">upgraded krawler job</a>.</p><p><strong>Major bug fixes:</strong><br> ✅ Filtering/Sorting in style manager affects filtering/sorting in the projects/views panels,<br> ✅ Improved animation performances,<br> ✅ Bearing not correctly taken into account in template context when using touch rotate,<br> ✅ Generated gateway token now takes appId into account.</p><p><strong>Major breaking changes for customized versions or iframe integration use cases:</strong><br> 💥 some events are <a href="https://kalisio.github.io/kano/guides/advanced-usage.html#frontend-events" target="_blank" rel="noreferrer">not emitted anymore</a> by default in iframe,<br> 💥 some events are now emitted with a <a href="https://kalisio.github.io/kano/guides/advanced-usage.html#frontend-events" target="_blank" rel="noreferrer">limited frequency</a>.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/14" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/14" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-4-0-may-21th-2025" tabindex="-1">v2.4.0 - May 21th, 2025 <a class="header-anchor" href="#v2-4-0-may-21th-2025" aria-label="Permalink to &quot;v2.4.0 - May 21th, 2025&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 New style manager for layer styling,<br> 👉 New selection manager to launch actions on selected features,<br> 👉 Application can now run offline with project data available in a zone,<br> 👉 Keycloak provider can be easily added for OAuth,<br> 👉 Import layer capabilities now available in globe,<br> 👉 Enhanced style support when importing KML or GeoJson,<br> 👉 Template context now available from iframe API,<br> 👉 Ability to animate moving/rotating objects in map from iframe API,<br> 👉 Ability to animate map move/rotation from iframe API,<br> 👉 Allow to stop map event propagation from iframe API,<br> 👉 More events emitted from iframe (touch events for map, move events for globe),<br> 👉 Realtime layers targeting any service can now be created/removed dynamically,<br> 👉 Automated focus on input controller when opening search tool,<br> 👉 Layers targetting OGC Web Services can send an additional header for authentication,<br> 👉 New position indicator,<br> 👉 Specific actions available to edit features of a layer.</p><p><strong>Major bug fixes:</strong><br> ✅ Map rotation using touch gesture can be costly,<br> ✅ Per-project permissions were not working correctly,<br> ✅ Globe activity cannot be initialized without a Cesium ion token.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/13" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/13" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-3-0-december-3rd-2024" tabindex="-1">v2.3.0 - December 3rd, 2024 <a class="header-anchor" href="#v2-3-0-december-3rd-2024" aria-label="Permalink to &quot;v2.3.0 - December 3rd, 2024&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Bumped NodeJS to v20,<br> 👉 Bumped CI to GitHub Actions,<br> 👉 Bumped CesiumJS to v1.117 (3D rendering engine),<br> 👉 Added <code>visibility</code> <a href="https://kalisio.github.io/kdk/api/map/map-mixins.html#map-style" target="_blank" rel="noreferrer">style property</a> that can be templated,<br> 👉 Added <a href="https://github.com/slutske22/leaflet-arrowheads" target="_blank" rel="noreferrer">leaflet-arrowheads</a> plugin to be able to create layers with related options,<br> 👉 Added ability to rotate the map with still some restrictions (weather, canvas and gradient path layers),<br> 👉 Added support for layers targetting PMTiles,<br> 👉 Added <code>highlightable</code> flag on layers,<br> 👉 iframe integration can now register client-side hooks on services,<br> 👉 iframe integration can now register a handler to manage real-time feature updates,<br> 👉 iframe integration can now track an entity in globe,<br> 👉 New map attribution component,<br> 👉 Ability to stack multiple timeseries with multi-selection,<br> 👉 Selecting features does not clean current probe anymore,<br> 👉 Now possible to avoid opening a widget on feature selection,<br> 👉 Now possible to configure pane z-index directly in layer definition,<br> 👉 Now possible to configure custom content in about box,<br> 👉 Imported GeoJson files can now include panes information,<br> 👉 (Dis)Connection popup can be deactivated by configuration,<br> 👉 Simplified domain management in client configuration.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 Enhanced rendering and legend of various data layer.</p><p><strong>Major bug fixes:</strong><br> ✅ Right opener not accessible when opening the right pane on mobile device,<br> ✅ PWA installation prompt visible in Firefox even if not built as a PWA,<br> ✅ <code>layer-updated</code> event was missing in globe activities.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/12" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/12" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-2-0-march-1st-2024" tabindex="-1">v2.2.0 - March 1st, 2024 <a class="header-anchor" href="#v2-2-0-march-1st-2024" aria-label="Permalink to &quot;v2.2.0 - March 1st, 2024&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Enhanced layer styling capabilities,<br> 👉 More ergonomic timeline component,<br> 👉 Enhanced location components,<br> 👉 Enhanced image capture component,<br> 👉 Allow to assign multiple legends to a layer,<br> 👉 Legend can now display information related to layer variables,<br> 👉 Legend can now display external OWS legends,<br> 👉 Emit catalog/feature service events for iframe integration,<br> 👉 Emit disconnect/reconnect events for iframe integration,<br> 👉 Allow to show/hide window controls,<br> 👉 Add a better map scale,<br> 👉 New events service that can be used to dispatch messages to all connected clients,<br> 👉 Added mapping projects management.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 Enhanced rendering and legend of various data layer.</p><p><strong>Major bug fixes:</strong><br> ✅ Search tool does not zoom when the result is not a point feature,<br> ✅ Mapillary marker is not moving when navigating with the viewer,<br> ✅ GSMap cloud cover layer not working anymore.</p><p><strong>Major breaking changes for customized versions or iframe integration use cases:</strong><br> 💥 changed layer variable unit from <code>units</code> to <code>unit</code>,<br> 💥 local storage keys now automatically prefixed by configured application name in kebab case (e.g. <code>my-app-jwt</code> for <code>MyApp</code> name),<br> 💥 layout elements in client config are now prefixed by <code>layout</code> (e.g. <code>layout.windows</code> or <code>layout.panes</code>), 💥 simple style cannot be defined anymore in feature <code>style</code> property,<br> 💥 engine/layer style definition (<a href="https://github.com/kalisio/kdk/issues/816" target="_blank" rel="noreferrer">details</a>).</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/11" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/10" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-1-0-septembre-25th-2023" tabindex="-1">v2.1.0 - Septembre 25th, 2023 <a class="header-anchor" href="#v2-1-0-septembre-25th-2023" aria-label="Permalink to &quot;v2.1.0 - Septembre 25th, 2023&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Migrated documentation to VitePress,<br> 👉 Progressive Web App,<br> 👉 Enhanced time input components,<br> 👉 Enhanced window behavior with size policy and responsive controls,<br> 👉 Real-time user data layer update for collaborative editing.</p><p><strong>Major bug fixes:</strong><br> ✅ Sending <code>updateLayer</code> command in iframe API closes feature edition,<br> ✅ Layer filters not correctly updated on tiled layers,<br> ✅ Favorite view items do not expand in catalog,<br> ✅ Bug report button not available in about dialog.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/10" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/9" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v2-0-0-june-29th-2023" tabindex="-1">v2.0.0 - June 29th, 2023 <a class="header-anchor" href="#v2-0-0-june-29th-2023" aria-label="Permalink to &quot;v2.0.0 - June 29th, 2023&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Bumped NodeJS to v16 and Feathers to v5,<br> 👉 Bumped Quasar to v2 and VueJS to v3,<br> 👉 Allow to create specific views from a layer,<br> 👉 Redirect to target URL once connected,<br> 👉 Provided a legend component.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 RTE generation data layer linked to <a href="https://github.com/kalisio/k-rte" target="_blank" rel="noreferrer">new krawler job</a>,<br> 👉 ICOS atmospheric data layer linked to <a href="https://github.com/kalisio/k-icos" target="_blank" rel="noreferrer">new krawler job</a>.</p><p><strong>Major bug fixes:</strong><br> ✅ Token without user ID not valid anymore to be used by iframe.</p><p><strong>Major breaking changes for customized versions or iframe integration use cases:</strong><br> 💥 renamed configuration/layers/categories files to <code>.cjs</code>,<br> 💥 backend configuration should comply with Feathers v5, e.g. authentication,<br> 💥 need to prefix layout path by <code>layout.</code> in frontend configuration,<br> 💥 default <code>mode</code> required for each layout element with content having multiple keys,<br> 💥 <code>window.widgets</code> frontend configuration path changed to <code>windows.top.widgets</code>,<br> 💥 static files moved from <code>src/statics</code> to <code>public</code>,<br> 💥 internal event bus refactoring (<code>on/off()</code> replaced <code>$on/off()</code>, added <code>$engineEvents</code> for map engine events).</p><p>Check <a href="https://nodejs.org/api/esm.html" target="_blank" rel="noreferrer">NodeJS documentation</a> for problems related to ECMAScript modules. Check <a href="https://quasar.dev/start/upgrade-guide" target="_blank" rel="noreferrer">Quasar upgrade guide</a> for problems related to Quasar v2/Vue v3.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/9" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/8" target="_blank" rel="noreferrer">KDK</a>.</p><h2 id="v1-6-0-august-30th-2022" tabindex="-1">v1.6.0 - August 30th, 2022 <a class="header-anchor" href="#v1-6-0-august-30th-2022" aria-label="Permalink to &quot;v1.6.0 - August 30th, 2022&quot;">​</a></h2><p><strong>Major enhancements:</strong><br> 👉 Catalog layout now includes favorite views,<br> 👉 Shapefile import is now supported,<br> 👉 Catalog with more default categories.</p><p><strong>Cartographic data enhancements:</strong><br> 👉 METAR data layer linked to <a href="https://github.com/kalisio/k-awc" target="_blank" rel="noreferrer">new krawler job</a>,<br> 👉 <a href="https://www.globalsmartrescue.com/little-alert-box/" target="_blank" rel="noreferrer">Little Alert Box</a> data layer.</p><p><strong>Major bug fixes:</strong><br> ✅ Geodesic circles cut when exceeding the viewport,<br> ✅ Some measure layers do not work anymore in 3D mode,<br> ✅ Forbid the window to pop out of the screen when moving or scaling it,<br> ✅ Memory leak in gradient path,<br> ✅ Real-time layers not correctly updated when time changes,<br> ✅ Impossible to remove min/max zoom levels once edited in the style,<br> ✅ Hiding/Showing a layer does not take into account configuration changes,<br> ✅ Popup active by default in layer style editor,<br> ✅ Editing the style of a web service layer (eg WMTS) makes it disappear.</p><p><strong>Major breaking changes for customized versions or iframe integration use cases:</strong><br> 💥 Default catalog categories moved from frontend to backend configuration.</p><p>More details on GitHub for <a href="https://github.com/kalisio/kano/milestone/7" target="_blank" rel="noreferrer">Kano</a> and <a href="https://github.com/kalisio/kdk/milestone/6" target="_blank" rel="noreferrer">KDK</a>.</p>',47),i=[n];function s(l,d,c,b,g,h){return t(),r("div",null,i)}const u=e(o,[["render",s]]);export{m as __pageData,u as default};
